from hypothesis import given, strategies as st

@given(
    text=st.text(min_size=0, max_size=2000),
    max_tokens=st.integers(min_value=1, max_value=500),
)
def test_chunk_sizes_respect_max_tokens(text, max_tokens):
    from ragapp.chunker import chunk_text, count_tokens
    chunks = chunk_text(text, max_tokens=max_tokens)
    assert all(count_tokens(c) <= max_tokens for c in chunks)

from hypothesis import given, example, strategies as st

@given(st.text())
@example(text="")                       # always test empty
@example(text="\u200b")                  # zero-width space — historical bug
@example(text="\ud83d\ude00")              # emoji (surrogate pair)
def test_chunker_is_lossless(text):
    from ragapp.chunker import chunk_text
    chunks = chunk_text(text, max_tokens=10)
    assert "".join(chunks) == text

