from hypothesis import strategies as st
from hypothesis.stateful import RuleBasedStateMachine, rule, invariant
import numpy as np
from ragapp.vectorstore import VectorStore


class VectorStoreMachine(RuleBasedStateMachine):
    def __init__(self):
        super().__init__()
        self.store = VectorStore(dim=4)
        self.expected = set()

    @rule(text=st.text(min_size=1, max_size=8))
    def add(self, text):
        vec = np.random.rand(4).astype("float32")
        self.store.add(text, vec)
        self.expected.add(text)

    @invariant()
    def all_added_are_searchable(self):
        if not self.expected:
            return
        any_text = next(iter(self.expected))
        assert self.store.contains(any_text)


TestVectorStore = VectorStoreMachine.TestCase

